@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Dispatcher")]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Shipment Management</PageTitle>

<h2>Shipment Management</h2>

<div class="mb-3 d-flex gap-2">
    <input type="text" class="form-control" placeholder="Filter by destination..."
           @bind="filterText" @bind:event="oninput" style="max-width: 300px;" />
    <select class="form-select" style="max-width: 200px;" @bind="filterStatus">
        <option value="">All Statuses</option>
        @foreach (var status in Enum.GetValues<ShipmentStatus>())
        {
            <option value="@status">@status</option>
        }
    </select>
    <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Create Shipment</h5>
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="CreateShipment">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row g-2 mb-2">
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Recipient Name" @bind="newShipment.RecipientName" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                    </div>
                </div>
                <div class="row g-2 mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Est. Delivery</label>
                        <input type="date" class="form-control"
                               @bind="newShipment.EstimatedDelivery" />
                    </div>
                    <div class="col-md-8">
                        <label class="form-label">Notes</label>
                        <input class="form-control" @bind="newShipment.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success me-2">Create</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (shipments == null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th @onclick='() => SortBy("TrackingNumber")' style="cursor:pointer">Tracking # ↕</th>
                <th @onclick='() => SortBy("Destination")' style="cursor:pointer">Destination ↕</th>
                <th @onclick='() => SortBy("Status")' style="cursor:pointer">Status ↕</th>
                <th>Recipient</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.RecipientName</td>
                    <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                    <td>
                        <button class="btn btn-sm btn-outline-primary" @onclick="() => StartEdit(shipment)">Edit</button>
                    </td>
                </tr>
                @if (editingId == shipment.Id)
                {
                    <tr>
                        <td colspan="6">
                            <div class="d-flex gap-2 align-items-center p-2 bg-light rounded">
                                <select class="form-select form-select-sm" style="max-width:160px" @bind="editStatus">
                                    @foreach (var s in Enum.GetValues<ShipmentStatus>())
                                    {
                                        <option value="@s">@s</option>
                                    }
                                </select>
                                <input type="date" class="form-control form-control-sm" style="max-width:160px"
                                       @bind="editEstDelivery" />
                                <input class="form-control form-control-sm" placeholder="Notes" @bind="editNotes" />
                                <button class="btn btn-sm btn-success" @onclick="SaveEdit">Save</button>
                                <button class="btn btn-sm btn-secondary" @onclick="() => editingId = null">Cancel</button>
                            </div>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string filterStatus = "";
    private string sortColumn = "TrackingNumber";
    private bool sortAscending = true;

    private bool showCreateForm;
    private CreateShipmentRequest newShipment = new();

    private int? editingId;
    private ShipmentStatus editStatus;
    private DateTime editEstDelivery;
    private string editNotes = "";

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private IEnumerable<ShipmentDto> FilteredShipments
    {
        get
        {
            var result = shipments!.AsEnumerable();
            if (!string.IsNullOrWhiteSpace(filterText))
                result = result.Where(s => s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase));
            if (!string.IsNullOrWhiteSpace(filterStatus) && Enum.TryParse<ShipmentStatus>(filterStatus, out var status))
                result = result.Where(s => s.Status == status);

            result = sortColumn switch
            {
                "Destination" => sortAscending ? result.OrderBy(s => s.Destination) : result.OrderByDescending(s => s.Destination),
                "Status" => sortAscending ? result.OrderBy(s => s.Status) : result.OrderByDescending(s => s.Status),
                _ => sortAscending ? result.OrderBy(s => s.TrackingNumber) : result.OrderByDescending(s => s.TrackingNumber)
            };
            return result;
        }
    }

    private void SortBy(string column)
    {
        if (sortColumn == column)
            sortAscending = !sortAscending;
        else
        {
            sortColumn = column;
            sortAscending = true;
        }
    }

    private void ShowCreateForm() => showCreateForm = true;

    private async Task CreateShipment()
    {
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments!.Insert(0, created);
        newShipment = new();
        showCreateForm = false;
    }

    private void StartEdit(ShipmentDto shipment)
    {
        editingId = shipment.Id;
        editStatus = shipment.Status;
        editEstDelivery = shipment.EstimatedDelivery;
        editNotes = shipment.Notes;
    }

    private async Task SaveEdit()
    {
        if (editingId is null) return;
        var updated = await ShipmentService.UpdateShipmentAsync(editingId.Value, new UpdateShipmentRequest
        {
            Status = editStatus,
            EstimatedDelivery = editEstDelivery,
            Notes = editNotes
        });
        var idx = shipments!.FindIndex(s => s.Id == editingId);
        if (idx >= 0) shipments[idx] = updated;
        editingId = null;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Track
            </button>
        </div>
    </div>
</div>

@if (notFound)
{
    <div class="alert alert-warning">No shipment found with tracking number <strong>@searchedNumber</strong>.</div>
}

@if (trackedShipment != null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <span><strong>Tracking:</strong> @trackedShipment.TrackingNumber</span>
            <span class="badge @GetStatusBadgeClass(trackedShipment.Status) fs-6">@trackedShipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt><dd>@trackedShipment.Origin</dd>
                        <dt>Destination</dt><dd>@trackedShipment.Destination</dd>
                        <dt>Recipient</dt><dd>@trackedShipment.RecipientName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt><dd>@trackedShipment.ShippedDate.ToString("yyyy-MM-dd")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            <strong class="text-primary">@trackedShipment.EstimatedDelivery.ToString("yyyy-MM-dd")</strong>
                        </dd>
                        @if (trackedShipment.ActualDelivery.HasValue)
                        {
                            <dt>Actual Delivery</dt>
                            <dd class="text-success fw-bold">@trackedShipment.ActualDelivery.Value.ToString("yyyy-MM-dd")</dd>
                        }
                    </dl>
                </div>
            </div>

            @if (!string.IsNullOrWhiteSpace(trackedShipment.Notes))
            {
                <div class="mt-2">
                    <strong>Notes:</strong> @trackedShipment.Notes
                </div>
            }

            <hr />
            <h6>Delivery Progress</h6>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(trackedShipment.Status)"
                     role="progressbar"
                     style="width: @(GetProgressPercent(trackedShipment.Status))%"
                     aria-valuenow="@GetProgressPercent(trackedShipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @trackedShipment.Status
                </div>
            </div>
        </div>
    </div>
}

<hr class="my-4" />

<h4>My Shipments</h4>
@if (myShipments == null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (myShipments.Count == 0)
{
    <p class="text-muted">No shipments associated with your account.</p>
}
else
{
    <table class="table">
        <thead>
            <tr><th>Tracking #</th><th>Destination</th><th>Status</th><th>Est. Delivery</th></tr>
        </thead>
        <tbody>
            @foreach (var s in myShipments)
            {
                <tr style="cursor:pointer" @onclick="() => SelectShipment(s)">
                    <td><code>@s.TrackingNumber</code></td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                    <td>@s.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private bool isSearching;
    private bool notFound;
    private ShipmentDto? trackedShipment;
    private List<ShipmentDto>? myShipments;

    protected override async Task OnInitializedAsync()
    {
        myShipments = await ShipmentService.GetMyShipmentsAsync();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isSearching = true;
        notFound = false;
        trackedShipment = null;
        searchedNumber = trackingNumber.Trim();

        trackedShipment = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);
        notFound = trackedShipment == null;
        isSearching = false;
    }

    private void SelectShipment(ShipmentDto shipment)
    {
        trackedShipment = shipment;
        trackingNumber = shipment.TrackingNumber;
        notFound = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Exception => 50,
        _ => 0
    };
}

