                                       @bind="editEstDelivery" />
                                <input class="form-control form-control-sm" placeholder="Notes" @bind="editNotes" />
                                <button class="btn btn-sm btn-success" @onclick="SaveEdit">Save</button>
                                <button class="btn btn-sm btn-secondary" @onclick="() => editingId = null">Cancel</button>
                            </div>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string filterStatus = "";
    private string sortColumn = "TrackingNumber";
    private bool sortAscending = true;

    private bool showCreateForm;
    private CreateShipmentRequest newShipment = new();

    private int? editingId;
    private ShipmentStatus editStatus;
    private DateTime editEstDelivery;
    private string editNotes = "";

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private IEnumerable<ShipmentDto> FilteredShipments
    {
        get
        {
            var result = shipments!.AsEnumerable();
            if (!string.IsNullOrWhiteSpace(filterText))
                result = result.Where(s => s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase));
            if (!string.IsNullOrWhiteSpace(filterStatus) && Enum.TryParse<ShipmentStatus>(filterStatus, out var status))
                result = result.Where(s => s.Status == status);

            result = sortColumn switch
            {
                "Destination" => sortAscending ? result.OrderBy(s => s.Destination) : result.OrderByDescending(s => s.Destination),
                "Status" => sortAscending ? result.OrderBy(s => s.Status) : result.OrderByDescending(s => s.Status),
                _ => sortAscending ? result.OrderBy(s => s.TrackingNumber) : result.OrderByDescending(s => s.TrackingNumber)
            };
            return result;
        }
    }

    private void SortBy(string column)
    {
        if (sortColumn == column)
            sortAscending = !sortAscending;
        else
        {
            sortColumn = column;
            sortAscending = true;
        }
    }

    private void ShowCreateForm() => showCreateForm = true;

    private async Task CreateShipment()
    {
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments!.Insert(0, created);
        newShipment = new();
        showCreateForm = false;
    }

    private void StartEdit(ShipmentDto shipment)
    {
        editingId = shipment.Id;
        editStatus = shipment.Status;
        editEstDelivery = shipment.EstimatedDelivery;
        editNotes = shipment.Notes;
    }

    private async Task SaveEdit()
    {
        if (editingId is null) return;
        var updated = await ShipmentService.UpdateShipmentAsync(editingId.Value, new UpdateShipmentRequest
        {
            Status = editStatus,
            EstimatedDelivery = editEstDelivery,
            Notes = editNotes
        });
        var idx = shipments!.FindIndex(s => s.Id == editingId);
        if (idx >= 0) shipments[idx] = updated;
        editingId = null;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-secondary"
    };
}
