                "Destination" => sortAscending ? result.OrderBy(s => s.Destination) : result.OrderByDescending(s => s.Destination),
                "Status" => sortAscending ? result.OrderBy(s => s.Status) : result.OrderByDescending(s => s.Status),
                _ => sortAscending ? result.OrderBy(s => s.TrackingNumber) : result.OrderByDescending(s => s.TrackingNumber)
            };
            return result;
        }
    }

    private void SortBy(string column)
    {
        if (sortColumn == column)
            sortAscending = !sortAscending;
        else
        {
            sortColumn = column;
            sortAscending = true;
        }
    }

    private void ShowCreateForm() => showCreateForm = true;

    private async Task CreateShipment()
    {
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments!.Insert(0, created);
        newShipment = new();
        showCreateForm = false;
    }

    private void StartEdit(ShipmentDto shipment)
    {
        editingId = shipment.Id;
        editStatus = shipment.Status;
        editEstDelivery = shipment.EstimatedDelivery;
        editNotes = shipment.Notes;
    }

    private async Task SaveEdit()
    {
        if (editingId is null) return;
        var updated = await ShipmentService.UpdateShipmentAsync(editingId.Value, new UpdateShipmentRequest
        {
            Status = editStatus,
            EstimatedDelivery = editEstDelivery,
            Notes = editNotes
        });
        var idx = shipments!.FindIndex(s => s.Id == editingId);
        if (idx >= 0) shipments[idx] = updated;
        editingId = null;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-secondary"
    };
}

