toolArgs.file_text:
@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Track
            </button>
        </div>
    </div>
</div>

@if (notFound)
{
    <div class="alert alert-warning">No shipment found with tracking number <strong>@searchedNumber</strong>.</div>
}

@if (trackedShipment != null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <span><strong>Tracking:</strong> @trackedShipment.TrackingNumber</span>
            <span class="badge @GetStatusBadgeClass(trackedShipment.Status) fs-6">@trackedShipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt><dd>@trackedShipment.Origin</dd>
                        <dt>Destination</dt><dd>@trackedShipment.Destination</dd>
                        <dt>Recipient</dt><dd>@trackedShipment.RecipientName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt><dd>@trackedShipment.ShippedDate.ToString("yyyy-MM-dd")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            <strong class="text-primary">@trackedShipment.EstimatedDelivery.ToString("yyyy-MM-dd")</strong>
                        </dd>
                        @if (trackedShipment.ActualDelivery.HasValue)
                        {
                            <dt>Actual Delivery</dt>
                            <dd class="text-success fw-bold">@trackedShipment.ActualDelivery.Value.ToString("yyyy-MM-dd")</dd>
                        }
                    </dl>
                </div>
            </div>

            @if (!string.IsNullOrWhiteSpace(trackedShipment.Notes))
            {
                <div class="mt-2">
                    <strong>Notes:</strong> @trackedShipment.Notes
                </div>
            }

            <hr />
            <h6>Delivery Progress</h6>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(trackedShipment.Status)"
                     role="progressbar"
                     style="width: @(GetProgressPercent(trackedShipment.Status))%"
                     aria-valuenow="@GetProgressPercent(trackedShipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @trackedShipment.Status
                </div>
            </div>
        </div>
    </div>
}

<hr class="my-4" />

<h4>My Shipments</h4>
@if (myShipments == null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (myShipments.Count == 0)
{
    <p class="text-muted">No shipments associated with your account.</p>
}
else
{
    <table class="table">
        <thead>
            <tr><th>Tracking #</th><th>Destination</th><th>Status</th><th>Est. Delivery</th></tr>
        </thead>
        <tbody>
            @foreach (var s in myShipments)
            {
                <tr style="cursor:pointer" @onclick="() => SelectShipment(s)">
                    <td><code>@s.TrackingNumber</code></td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                    <td>@s.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private bool isSearching;
    private bool notFound;
    private ShipmentDto? trackedShipment;
    private List<ShipmentDto>? myShipments;

    protected override async Task OnInitializedAsync()
    {
        myShipments = await ShipmentService.GetMyShipmentsAsync();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isSearching = true;
        notFound = false;
        trackedShipment = null;
        searchedNumber = trackingNumber.Trim();

        trackedShipment = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);
        notFound = trackedShipment == null;
        isSearching = false;
    }

    private void SelectShipment(ShipmentDto shipment)
    {
        trackedShipment = shipment;
        trackingNumber = shipment.TrackingNumber;
        notFound = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.Pending => "bg-warning text-dark",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Exception => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Exception => 50,
        _ => 0
    };
}

