using System.Security.Claims;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            return await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => ToDto(s))
                .ToListAsync();
        }).RequireAuthorization("DispatcherPolicy");

        group.MapGet("/mine", async (ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            var email = user.FindFirstValue(ClaimTypes.Email) ?? "";
            return await db.Shipments
                .Where(s => s.CustomerEmail == email)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => ToDto(s))
                .ToListAsync();
        });

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(ToDto(shipment));
        });

        group.MapPost("/", async ([FromBody] CreateShipmentRequest request, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = GenerateTrackingNumber(),
                Origin = request.Origin,
                Destination = request.Destination,
                RecipientName = request.RecipientName,
                CustomerEmail = request.CustomerEmail,
                Status = ShipmentStatus.Pending,
                ShippedDate = DateTime.UtcNow,
                EstimatedDelivery = request.EstimatedDelivery,
                Notes = request.Notes
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/track/{shipment.TrackingNumber}", ToDto(shipment));
        }).RequireAuthorization("DispatcherPolicy");

        group.MapPut("/{id:int}", async (int id, [FromBody] UpdateShipmentRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = request.Status;
            shipment.EstimatedDelivery = request.EstimatedDelivery;
            shipment.Notes = request.Notes;
            if (request.Status == ShipmentStatus.Delivered && shipment.ActualDelivery is null)
                shipment.ActualDelivery = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.Ok(ToDto(shipment));
        }).RequireAuthorization("DispatcherPolicy");
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        CustomerEmail = s.CustomerEmail,
        Notes = s.Notes
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
