+using Microsoft.EntityFrameworkCore;
+using ShipmentTracker.Client.Models;
+using ShipmentTracker.Client.Services;
+using ShipmentTracker.Data;
+
+namespace ShipmentTracker.Services;
+
+/// <summary>
+/// Server-side implementation used during prerendering.
+/// </summary>
+public class ServerShipmentService(ApplicationDbContext db, IHttpContextAccessor httpContextAccessor) : IShipmentService
+{
+    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
+    {
+        return await db.Shipments
+            .OrderByDescending(s => s.ShippedDate)
+            .Select(s => MapToDto(s))
+            .ToListAsync();
+    }
+
+    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
+    {
+        var email = httpContextAccessor.HttpContext?.User?.FindFirst(System.Security.Claims.ClaimTypes.Email)?.Value ?? "";
+        return await db.Shipments
+            .Where(s => s.CustomerEmail == email)
+            .OrderByDescending(s => s.ShippedDate)
+            .Select(s => MapToDto(s))
+            .ToListAsync();
+    }
+
+    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
+    {
+        var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
+        return shipment is null ? null : MapToDto(shipment);
+    }
+
+    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request)
+    {
+        var shipment = new Shipment
+        {
+            TrackingNumber = $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}",
+            Origin = request.Origin,
+            Destination = request.Destination,
+            RecipientName = request.RecipientName,
+            CustomerEmail = request.CustomerEmail,
+            Status = ShipmentStatus.Pending,
+            ShippedDate = DateTime.UtcNow,
+            EstimatedDelivery = request.EstimatedDelivery,
+            Notes = request.Notes
+        };
+        db.Shipments.Add(shipment);
+        await db.SaveChangesAsync();
+        return MapToDto(shipment);
+    }
+
+    public async Task<ShipmentDto> UpdateShipmentAsync(int id, UpdateShipmentRequest request)
+    {
+        var shipment = await db.Shipments.FindAsync(id)
+            ?? throw new InvalidOperationException("Shipment not found.");
+        shipment.Status = request.Status;
+        shipment.EstimatedDelivery = request.EstimatedDelivery;
+        shipment.Notes = request.Notes;
+        if (request.Status == ShipmentStatus.Delivered && shipment.ActualDelivery is null)
+            shipment.ActualDelivery = DateTime.UtcNow;
+        await db.SaveChangesAsync();
+        return MapToDto(shipment);
+    }
+
+    private static ShipmentDto MapToDto(Shipment s) => new()
+    {
+        Id = s.Id,
+        TrackingNumber = s.TrackingNumber,
+        Origin = s.Origin,
+        Destination = s.Destination,
+        Status = s.Status,
+        ShippedDate = s.ShippedDate,
+        EstimatedDelivery = s.EstimatedDelivery,
+        ActualDelivery = s.ActualDelivery,
+        RecipientName = s.RecipientName,
+        CustomerEmail = s.CustomerEmail,
+        Notes = s.Notes
+    };
+}
