                Origin = "Berlin, Germany",
                Destination = "São Paulo, Brazil",
                Status = ShipmentStatus.Pending,
                ShippedDate = DateTime.UtcNow,
                EstimatedDelivery = DateTime.UtcNow.AddDays(7),
                RecipientName = "Carlos Mendes",
                CustomerEmail = "carlos@example.com",
                Notes = "Requires signature"
            },
            new Shipment
            {
                TrackingNumber = "SHP-20260515-400004",
                Origin = "Shanghai, China",
                Destination = "Los Angeles, CA",
                Status = ShipmentStatus.Delivered,
                ShippedDate = DateTime.UtcNow.AddDays(-8),
                EstimatedDelivery = DateTime.UtcNow.AddDays(-1),
                ActualDelivery = DateTime.UtcNow.AddDays(-1),
                RecipientName = "Diana Lee",
                CustomerEmail = "diana@example.com",
                Notes = ""
            },
            new Shipment
            {
                TrackingNumber = "SHP-20260521-500005",
                Origin = "Mumbai, India",
                Destination = "Dubai, UAE",
